head.script:
//==================================================================================================================
// id       : ar_104_01_01b
// 이름     : House Air Waybill(Outbound)
// 경로     : 해외물류
// 작 성 자 : 김용호
// 작 업 일 : 2026-01-15
// 사용계정 : 내부
// 비고     :
//
// 업로드   :
// 다운로드 :  
// 레포트   :
// 호출     : 
//==================================================================================================================

scwin.cvsslMgntNo = "";
scwin.p_kcomcd = "";
scwin.p_blno = "";
scwin.p_mblno = "";
scwin.p_type = "";

scwin.lobranCd = "";
scwin.empNo = "";
scwin.p_lobranCd = "";
scwin.p_lobranNm = "";
scwin.userId = "";
scwin.userDTOJson = {};
scwin.p_clntNo = "";
scwin.p_clntNm = "";
scwin.strCurDate = "";
scwin.hd_kcomcd = "";
scwin.hd_iogb = "";
scwin.hd_frpc = "";
scwin.hd_otpc = "";
scwin.hd_shipgb = "";
scwin.hd_oldmhno = "";
scwin.txt_nonm = "";
scwin.txt_unit = "";
scwin.ed_arcd = "";
scwin.txt_arnm = "";
scwin.lc_lrgb = "";
scwin.txt_updid = "";
scwin.txt_upddt = "";

scwin.MSG_LO_WRN_001 = "해당 B/L 번호로 복사 하시겠습니까?";
scwin.MSG_LO_WRN_002 = "마감된 자료 입니다. 수정 할 수 없습니다.";
scwin.MSG_LO_WRN_003 = "이미 존재하는 House B/L No : %1 가 있습니다.";
scwin.MSG_LO_WRN_005 = "이미 인보이스  발행 되어 삭제 불가능 합니다.";
scwin.MSG_LO_WRN_006 = "이미 운임이  발행 되어 변경 불가능 합니다.";
scwin.MSG_LO_WRN_007 = "House B/L No 가 변경 되었습니다.";
scwin.MSG_LO_WRN_008 = "이미 전표가 발행  되어 변경 불가능 합니다.";
scwin.MSG_LO_WRN_009 = "Department 가 변경 되었습니다.";
scwin.MSG_LO_WRN_010 = "1GG 부서 코드는 사용하실 수 없습니다. ";
scwin.MSG_LO_WRN_013 = "Customer와 Dept가 일치하지 않습니다. \n거래처별 매출귀속 정의 화면에서 정보를 확인하세요.";

scwin.processFlag = "";
scwin.actionFlag = "";
scwin.linkType = "New";
scwin.spRtn = "";
scwin.spMsg = "";
scwin.freightYn = "";
scwin.vLobranCd = "";
scwin.vLobranNm = "";


//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = async function() {
    scwin.cvsslMgntNo = $c.data.getParameter("cvsslMgntNo") || "";
    scwin.p_kcomcd = $c.data.getParameter("kcomcd") || "";
    scwin.p_blno = $c.data.getParameter("blno") || "";
    scwin.p_mblno = $c.data.getParameter("mblno") || "";
    scwin.p_type = $c.data.getParameter("type") || "";

    scwin.lobranCd = $c.data.getMemInfo("lobranCd") || " ";
    scwin.empNo = $c.data.getMemInfo("userId") || "";
    scwin.p_lobranCd = $c.data.getMemInfo("lobranCd") || " ";
    scwin.p_lobranNm = $c.data.getMemInfo("lobranNm") || "";
    scwin.userId = $c.data.getMemInfo("userId") || "";
    scwin.userDTOJson = $c.data.getMemInfo() || {};
    scwin.p_clntNo = $c.data.getMemInfo("clntNo") || "";
    scwin.p_clntNm = $c.data.getMemInfo("clntNm") || ""; // TODO: memInfo key 확인
    scwin.vLobranCd = $c.data.getMemInfo("lobranCd") || " ";
    scwin.vLobranNm = $c.data.getMemInfo("lobranNm") || "";

    scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd") || ""; // TODO: 포맷 확인
    scwin.hd_kcomcd = scwin.p_kcomcd || "DBEX";
    scwin.hd_iogb = "O";
    scwin.hd_frpc = "";
    scwin.hd_otpc = "";
    scwin.hd_shipgb = "";
    scwin.hd_oldmhno = "";
    scwin.txt_nonm = "";
    scwin.txt_unit = "";
    scwin.ed_arcd = "";
    scwin.txt_arnm = "";
    scwin.lc_lrgb = "";
    scwin.txt_updid = "";
    scwin.txt_upddt = "";

    scwin._bindOnBlur("ed_agcd", scwin.ed_agcd_onblur);
    scwin._bindOnBlur("ed_dpcd", scwin.ed_dpcd_onblur);
    scwin._bindOnBlur("ed_dept", scwin.ed_dept_onblur);
    scwin._bindOnBlur("ed_sacd", scwin.ed_sacd_onblur);
    scwin._bindOnBlur("ed_mftpacd", scwin.ed_mftpacd_onblur);
    scwin._bindOnBlur("ed_mwarecd", scwin.ed_mwarecd_onblur);
    scwin._bindOnBlur("ed_warecd", scwin.ed_warecd_onblur);
    scwin._bindOnBlur("ed_ascdpic", scwin.ed_ascdpic_onblur);
    scwin._bindOnBlur("ed_pncdpic", scwin.ed_pncdpic_onblur);
    scwin._bindOnBlur("ed_blpic", scwin.ed_blpic_onblur);

    const codeOptions = [
        { grpCd: "IL005", compID: "lc_inco"},
    ];
    $c.data.setCommonCode(codeOptions, function() {
        lc_inco.setSelectedIndex(-1);
    });

    await scwin.f_OnLoad();
};

scwin.f_OnLoad = async function() {
	scwin.f_initSetTab();
};

scwin.onUdcCompleted = async function() {
	// scwin._ensureRow(ds_HouseBillSearch);
	scwin._ensureRow(ds_MasterBillSearch);
	scwin._ensureRow(ds_empNo);

	scwin.f_Set("INIT");

	await scwin.f_getParametrSetting(); // link처리

	$c.gus.cfDisableObjects([txt_updid]);
	$c.gus.cfDisableObjects([txt_upddt]);
};


//---------------------------------------------------------
// Parameter Setting
//---------------------------------------------------------
scwin.f_getParametrSetting = async function() {
    var kcomcd = scwin.p_kcomcd;
    var blno = scwin.p_blno;
    var type = scwin.p_type;
    var mblno = scwin.p_mblno;

    scwin.linkType = type;

    if ($c.str.trim(scwin.linkType) == "HawbCreate") {
        if (mblno == null || mblno == "") {
            return false;
        }

        await scwin.f_Create();

        scwin.hd_kcomcd = kcomcd;
        ed_mblno.setValue(mblno);

        await scwin.f_MasterConsolNoLoading();
        if (scwin.actionFlag == "Create") {
            await scwin.f_RetrieveMasterInfo();	//마스터에서 정보 뿌려줌
        }
        ed_blno.focus();

    } else if ($c.str.trim(scwin.linkType) == "ColoadHawbCreate") {
        if (mblno == null || mblno == "") {
            return false;
        }

        await scwin.f_Create();

        scwin.hd_kcomcd = kcomcd;
        ed_mblno.setValue(mblno);

        scwin.f_MasterConsolNoLoading();
        if (scwin.actionFlag == "Create") {
            await scwin.f_RetrieveMasterBookinInfo();	//마스터 부킹에서 정보 뿌려줌
        }
        ed_blno.focus();

    } else {
        if (blno == null || blno == "") {
            return false;
        }
        scwin.hd_kcomcd = kcomcd;
        ed_blno.setValue(blno);

        scwin.f_MhnoLoading();
        scwin.f_Retrieve();
    }
};


//-------------------------------------------------------------------------
// 화면 초기화
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function(gubun) {
    switch (gubun) {
        case "Create":
            chb_frpc1.setValue("1");
            chb_frpc2.setValue("0");
            chb_otpc1.setValue("1");
            chb_otpc2.setValue("0");
            ds_hmhno.removeAll();
            scwin._resetAutoComplete(lc_hmhno);
            // ed_mftpacd.setValue("");
            scwin.txt_unit = "";
            ed_srno.setValue("");
            ed_mblno.setValue("");
            $c.gus.cfEnableObjects([ed_srno]);
            $c.gus.cfEnableObjects([ed_mblno]);
            rd_cgtype.setValue("L");
            rd_tplgb.setValue("N");
            ed_cucd.setValue("KRW");
            ed_acif1.setValue("FREIGHT PREPAID");
            ed_dvcr.setValue("N.V.D");
            ed_dvct.setValue("");
            ed_insu.setValue("NIL");
            rd_ergb.setValue("E");
            ed_blno.setValue("");
            ed_blno.focus();
            break;

        case "Copy":
            ed_blno.setValue("");
            ds_hmhno.removeAll();
            scwin._resetAutoComplete(lc_hmhno);
            // ed_mftpacd.setValue("");
            scwin.txt_unit = "";
            ed_srno.setValue("");
            ed_mblno.setValue("");
            scwin.hd_oldmhno = "";
            ed_blno.focus();
            break;

        default:
            break;
    }
};

//---------------------------------------------------------
// TAB 초기화
//---------------------------------------------------------
scwin.f_initSetTab = function() {
    //$c.gus.cfEnableObjects([tr_tab_center0, tr_tab_center1, tr_tab_center3]); // TODO: tab ID 매핑 확인
    tab_main.setSelectedTabIndex(0);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    if (ed_blno.getValue() != "") {
        ds_HouseBillInfo.removeAll();
        ds_HouseLicenseInfo.removeAll();

        await scwin.f_ProcessBinding(ds_HouseBillSearch, "HouseBillSearch");
        await $c.sbm.execute(sbm_Retrieve);

    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["House B/L No"]);
        ed_blno.focus();
    }
};

// Master info 조회
scwin.f_RetrieveMasterInfo = async function() {
    if ($c.str.trim(ed_mblno.getValue()) != "") {
        await scwin.f_ProcessBinding(ds_HouseBillSearch, "RetrieveMasterInfo");
        await $c.sbm.execute(sbm_RetrieveMaster);
    }
};

// Master booking info 조회
scwin.f_RetrieveMasterBookinInfo = async function() {
    if ($c.str.trim(ed_mblno.getValue()) != "") {
        scwin.f_ProcessBinding(ds_MasterBillSearch, "MasterBillSearch");
        await $c.sbm.execute(sbm_RetrieveMasterBooking);
    }
};

//-------------------------------------------------------------------------
// Booking 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveBookingInfo = async function() {
    if (ed_srno.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking No"]);

    } else {
        scwin.f_ProcessBinding(ds_HouseBillSearch, "CustomerBookingSearch");
        $c.sbm.execute(sbm_RetrieveBookigInfo);
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_ProcessResult = async function(gubun) {

    switch (gubun) {
        case "None":
            scwin.f_Set("INIT");
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003); // 해당 되는 자료가 없습니다.
            ed_blno.focus();
            break;

        case "HouseInfo":
            scwin.f_Set("RETRIEVE");
            scwin.f_SettingValue();
            scwin.f_MhnoLoading();
            scwin.f_InvoiceCheck_All("B"); //운임 발생시 ITEM , Department 수정 못 하게 하기 위해 검색
            break;

        case "NotExistMasterBookingInfo":
            scwin.processFlag = "None";
            ed_mblno.setValue("");
            break;

        case "ExistMasterBookingInfo":
            scwin.processFlag = "ExistMasterBookingInfo";
            scwin.f_MasterBookingListBinding("Retrieve", ds_MasterBookingInfo, ds_HouseBillInfo);
            break;

        default:
            break;
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveCustomerBookingResult = async function(gubun) {
    switch (gubun) {
        case "None":
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003);
            ed_srno.setValue("");
            break;

        case "BookingInfo":
            if (ds_CustomerBookingInfo.getRowCount() == 0) {
                return false;
            }

            var rowIndex = 0; //ds_CustomerBookingInfo.getRowPosition();

            if (ds_CustomerBookingInfo.getCellData(rowIndex, "blno") != "") {
                await $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_003, [ds_CustomerBookingInfo.getCellData(rowIndex, "blno")]); // 이미 존재하는 House B/L No : @ 가 있습니다.";
                ed_srno.setValue("");
                return false;
            }

            ed_srno.setValue(ds_CustomerBookingInfo.getCellData(rowIndex, "srno"));
            ed_shcd.setValue(ds_CustomerBookingInfo.getCellData(rowIndex, "shcd"));
            if ($c.str.trim(ed_shcd.getValue()) != "") {
                scwin.afterSetBookinfNo = true;
                await scwin.f_PopUp("Shipper", "T", "F", "F");
            }

            ed_cncd.setValue(ds_CustomerBookingInfo.getCellData(rowIndex, "cncd"));
            if ($c.str.trim(ed_cncd.getValue()) != "") {
                await scwin.f_PopUp("Consignee", "T", "F", "F");
            }

            ed_nocd.setValue(ds_CustomerBookingInfo.getCellData(rowIndex, "pncd"));
            txt_nonm.setValue("");
            if ($c.str.trim(ed_nocd.getValue()) != "") {
                await scwin.f_PopUp("Partner", "T", "F", "F");
            }

            ed_ascd.setValue(ds_CustomerBookingInfo.getCellData(rowIndex, "ascd"));
            txt_asnm.setValue("");
            if ($c.str.trim(ed_ascd.getValue()) != "") {
                await scwin.f_PopUp("Customer", "T", "F", "F");
            }

            ed_sacd.setValue(ds_CustomerBookingInfo.getCellData(rowIndex, "sacd"));
            txt_sanm.setValue(ds_CustomerBookingInfo.getCellData(rowIndex, "sanm"));
            ed_itcd.setValue(ds_CustomerBookingInfo.getCellData(rowIndex, "itcd"));
            txt_itnm.setValue(ds_CustomerBookingInfo.getCellData(rowIndex, "itnm"));

            //2020.03.02 국제영업3팀 개선사항 : 부킹에 등록된 ITEM 없을 경우 자동으로 30000000 (일반화물) 으로 기입 처리
            if (txt_itnm.getValue() == "") {
                ed_itcd.setValue("30000000");
                txt_itnm.setValue("일반화물");
            }

            if ($c.str.trim(ed_ascd.getValue()) != "") {
                await scwin.f_departmentInfo();
            }

            // Booking 번호 검색 후 복사 실행
            if (scwin.processFlag == "Copy") {
                var hbRowIndex = scwin._getRowIndex(ds_HouseBillInfo);
                var licRowIndex = scwin._getRowIndex(ds_HouseLicenseInfo);
                if (ds_HouseBillInfo.getRowCount() > 0) {
                    ds_HouseBillInfo.modifyRowStatus(hbRowIndex, "C");
                }
                if (ds_HouseLicenseInfo.getRowCount() > 0) {
                    ds_HouseLicenseInfo.modifyRowStatus(licRowIndex, "C");
                }

                scwin.f_Save();
                scwin.processFlag = "None";
            }

            //기본으로 등록자 ID 기입 처리
            txt_blpic.setValue("");
            if (ed_blpic.getValue() == "") {
                ed_blpic.setValue(scwin.userId.replace(/[^0-9]/g, ""));
                txt_blpic.setValue(await scwin.f_PopUp("B/L PIC", "T"));
            }
            break;

        default:
            break;
    }
};


//-------------------------------------------------------------------------
//House no 자동 생성 하기 위한 param 설정
//-------------------------------------------------------------------------
scwin.f_HblNoStockPram = function() {
    ds_HblStockNoInfo.setEmptyValue();
    ds_HblStockNoInfo.set("kcomcd", scwin.hd_kcomcd);
    ds_HblStockNoInfo.set("dept", "1GG");
};


//-------------------------------------------------------------------------
//Invoice Chedk
//-------------------------------------------------------------------------
scwin.f_InvoiceCheck_All = async function(gbun) {
    var hbRowIndex = scwin._getRowIndex(ds_HouseBillInfo);
    dma_InvoiceCheckParam.set("odrNo", ds_HouseBillInfo.getCellData(hbRowIndex, "odrNo"));
    dma_InvoiceCheckParam.set("mblHblCls", "H");
    dma_InvoiceCheckParam.set("kcomcd", scwin.hd_kcomcd);   // 법인코드
    dma_InvoiceCheckParam.set("blNo", ed_blno.getValue());  // Master Bill No
    dma_InvoiceCheckParam.set("mhno", lc_hmhno.getValue() || ""); // 해운/항공 구분
    dma_InvoiceCheckParam.set("gbun", gbun == "B" ? "B" : "F");

    scwin.spMsg = "";
    scwin.spRtn = "-1";
    let e = await $c.sbm.execute(sbm_InvoiceCheck);

    if (e.responseJSON.resultDataSet[0].Code < 0) return;
    if (e.responseJSON.OUT_DS1.length > 0) {
        // if (ds_InvoiceCheck.getRowCount() > 0) {
            var invRowIndex = scwin._getRowIndex(ds_InvoiceCheck);
            scwin.spMsg = ds_InvoiceCheck.getCellData(invRowIndex, "spMsg");
            scwin.spRtn = ds_InvoiceCheck.getCellData(invRowIndex, "spRtn");
        // }
    }
    scwin.freightYn = scwin.spRtn;
};


//-------------------------------------------------------------------------
//조회조건 바인딩
//-------------------------------------------------------------------------
scwin.f_ProcessBinding = async function(ds, gubun) {
    var rowIndex = -1;

    switch (gubun) {
        case "HouseBillSearch":     // ds_HouseBillSearch
            ds.setEmptyValue();
            ds.set("kcomcd", scwin.hd_kcomcd);
            ds.set("blno", $c.str.trim(ed_blno.getValue()));
            ds.set("mhno", lc_hmhno.getValue() || "");
            ds.set("iogb", scwin.hd_iogb);
            break;

        case "HouseBillSave":       // ds_HouseBillInfo
            rowIndex = scwin._getRowIndex(ds);
            ds.setRowPosition(rowIndex);
            ds.setCellData(rowIndex, "kcomcd", scwin.hd_kcomcd);
            ds.setCellData(rowIndex, "iogb", scwin.hd_iogb);
            ds.setCellData(rowIndex, "blno", $c.str.trim(ed_blno.getValue()));
            ds.setCellData(rowIndex, "mhno", lc_hmhno.getValue() || "");
            // ds.setCellData(rowIndex, "mftpacd", $c.str.trim(ed_mftpacd.getValue()));
            break;

        case "HouseLicenseSave":    // ds_HouseLicenseInfo
            rowIndex = scwin._getRowIndex(ds);
            ds.setRowPosition(rowIndex);
            ds.setCellData(rowIndex, "kcomcd", scwin.hd_kcomcd);
            ds.setCellData(rowIndex, "blno", $c.str.trim(ed_blno.getValue()));
            ds.setCellData(rowIndex, "mhno", lc_hmhno.getValue() || "");
            break;

        case "CustomerBookingSearch":   // ds_HouseBillSearch
            ds.setEmptyValue();
            ds.set("kcomcd", scwin.hd_kcomcd);
            ds.set("srno", $c.str.trim(ed_srno.getValue()));
            ds.set("iogb", scwin.hd_iogb);
            break;

        case "HouseBillCheck":      // 사용X
            ds.removeAll();
            ds.set("kcomcd", scwin.hd_kcomcd);
            ds.set("blno", $c.str.trim(ed_blno.getValue()));
            ds.set("iogb", scwin.hd_iogb);
            break;

        case "RetrieveMasterInfo":  // ds_HouseBillSearch
            ds.setEmptyValue();
            ds.set("kcomcd", scwin.hd_kcomcd);
            ds.set("iogb", scwin.hd_iogb);
            ds.set("blno", $c.str.trim(ed_mblno.getValue()));
            break;

        case "MasterBillSearch":    // ds_MasterBillSearch
            ds.removeAll();
            scwin._insertRow(ds);
            rowIndex = scwin._getRowIndex(ds);
            ds.setRowPosition(rowIndex);
            ds.setCellData(rowIndex, "kcomcd", scwin.hd_kcomcd);
            ds.setCellData(rowIndex, "blno", $c.str.trim(ed_mblno.getValue()));
            ds.setCellData(rowIndex, "mhno", lc_hmhno.getValue() || "");
            ds.setCellData(rowIndex, "iogb", scwin.hd_iogb);
            break;

        default:
            break;
    }
};


//-------------------------------------------------------------------------
// 자료를 가져온  후 화면 셋팅
//-------------------------------------------------------------------------
scwin.f_SettingValue = function() {
    if (ed_srno.getValue() == "") {
        $c.gus.cfEnableObjects([ed_srno]);
    } else {
        $c.gus.cfDisableObjects([ed_srno]);
    }

    if (ed_mblno.getValue() == "") {
        $c.gus.cfEnableObjects([ed_mblno]);
    } else {
        $c.gus.cfDisableObjects([ed_mblno]);
    }

    scwin.f_FreightTypeGetting();
};


//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function() {
    if (scwin.actionFlag == "Create") {
        scwin.f_Set("INIT");
        scwin.processFlag = "None";
    } else {
        scwin.f_Set("RETRIEVE");
    }
    ds_HouseBillInfo.undoAll();
    ds_HouseLicenseInfo.undoAll();
};


//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = async function() {
    ds_HouseBillInfo.removeAll();
    ds_HouseBillInfo.insertRow();
    ds_HouseBillInfo.setRowPosition(0);

    ds_HouseLicenseInfo.removeAll();
    totalRow.setValue("0");

    scwin.actionFlag = "Create";
    scwin.f_Set("CREATE");

    txt_blpic.setValue("")

    //추가
    ed_mftpkg.setValue("0");
    ed_mftwht.setValue("0");
    ed_tcwht.setValue("0");
    ed_ediwht.setValue("0");

    //기본으로 등록자 ID 기입 처리
    if (txt_blpic.getValue() == "") {
        ed_blpic.setValue(scwin.userId.replace(/[^0-9]/g, ""));
        await scwin.f_PopUp("B/L PIC", "T");
    }
};



//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function() {
    scwin.actionFlag = "Update";
    scwin.f_Set("UPDATE");

    if ($c.str.trim(ed_agcd.getValue()) == "") {
        $c.gus.cfDisableObjects([lc_lrgb]);
    } else {
        $c.gus.cfEnableObjects([lc_lrgb]);
    }
    $c.gus.cfDisableObjects([ed_dept, txt_deptnm, udc_dept]);
};


scwin.f_FileDownload = async function() {
    var opts = {
        width : 870,
        height : 400
    };
    var data = {
        houseNo: ed_blno.getValue(),
    };
    var returnValue = await $c.win.openPopup("/ui/il/common/xml/ilCommonFilePopup.xml", opts, data);
};


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function() {
    if (scwin.actionFlag == "Create" || scwin.actionFlag == "Copy") {
        await scwin.f_ProcessBinding(ds_HouseBillSearch, "HouseBillSearch");
        await $c.sbm.execute(sbm_RetrieveHouseBillCheck);
    }

    await scwin.f_Save_after();
};

scwin.f_Save_after = async function() {
    scwin.f_FreightTypeSetting();

    if (ds_HouseBillInfo.getModifiedIndex().length > 0 || ds_HouseLicenseInfo.getModifiedIndex().length > 0) {
        // scwin._syncHiddenToDs();
        await scwin.f_ProcessBinding(ds_HouseBillInfo, "HouseBillSave");
        await scwin.f_ProcessBinding(ds_HouseLicenseInfo, "HouseLicenseSave");
        scwin.f_selectTabMenu(0);   // 저장 전 TAB FOCUS  이동
        scwin.f_FreightTypeSetting();

        if (await scwin.f_ReqFieldChk()) {
            scwin.actionFlag = "Save";
            scwin.f_HblNoStockPram();

            var hbRowIndex = scwin._getRowIndex(ds_HouseBillInfo);
            if ($c.str.trim(ed_agcd.getValue()) == "") {
                ds_HouseBillInfo.setCellData(hbRowIndex, "shipgb", "C");
            } else {
                ds_HouseBillInfo.setCellData(hbRowIndex, "shipgb", "L");
            }

            // UserStatus-JSP 화면에 Head 와 Body(그리드)가 있을경우 Body가 변경 될 경우 무조건 Head도 서버 로 전송 해서 업데이트 하기 위해서 사용 됨
            if (ds_HouseBillInfo.getCellData(hbRowIndex, "status") == "U") {
                ds_HouseBillInfo.setCellData(hbRowIndex, "status", "");
            } else {
                ds_HouseBillInfo.setCellData(hbRowIndex, "status", "U");
            }

            if (ed_shCtcd.getValue() == "") {
                await $c.win.alert("Shipper Country code is mandatory.");
                return false;
            }

            if (ed_cnCtcd.getValue() == "") {
                await $c.win.alert("Consignee Country code is mandatory.");
                return false;
            }

            if (ed_mwarecd.getValue() == "") {
                await $c.win.alert("적재장소는 필수입니다.");
                return false;
            }

            if (ed_warecd.getValue() == "") {
                await $c.win.alert("장치장소는 필수입니다.");
                return false;
            }

            // B/L PIC값이 없을때 등록자 아이디로 입력(PIC값이 null되는걸 방지)
            if (ed_blpic.getValue() == "") {
                txt_blpic.setValue("");
                ds_HouseBillInfo.setCellData(hbRowIndex, "pic", scwin.userId);
            }

            await $c.sbm.execute(sbm_Save);
        }

    } else {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["House Info"]); //@은(는) 변경된 사항이 없습니다.
    }
};


//유효성검사
scwin.f_ReqFieldChk = async function() {
    if (ed_srno.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking No"]);
        ed_srno.focus();
        return false;
    }

    if (txt_shnm1.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Shipper Name"]);
        txt_shnm1.focus();
        return false;
    }

    if (txt_shnm2.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Shipper Name"]);
        txt_shnm2.focus();
        return false;
    }

    if (txt_cnnm1.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Consignee Name"]);
        txt_cnnm1.focus();
        return false;
    }

    if (txt_cnnm2.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Consignee Name"]);
        txt_cnnm2.focus();
        return false;
    }

    if (ed_srno.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking No"]);
        ed_srno.focus();
        return false;
    }

    if (ed_ondt.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Onboard Date"]);
        ed_ondt.focus();
        return false;
    }

    if (ed_avdt.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Arrival Date"]);
        ed_avdt.focus();
        return false;
    }

    // 날짜 범위 확인
    if (!$c.gus.cfIsAfterDate(ed_ondt.getValue(), ed_avdt.getValue())) {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_048, ["Onboard Date", "Arrival Date"]);  //@은(는) 보다 작아야 합니다.
        ed_ondt.focus();
        return false;
    }

    //ETD-ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없다.
    if ($c.gus.cfMonthsBetween(scwin._toDate(scwin.strCurDate), scwin._toDate(ed_ondt.getValue())) > 3) {
        await $c.win.alert("Onboard Date가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다.");
        tab_main.setSelectedTabIndex(0);
        ed_ondt.focus();
        return false;
    }

    //ETD-ETA가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없다.
    if ($c.gus.cfMonthsBetween(scwin._toDate(scwin.strCurDate), scwin._toDate(ed_avdt.getValue())) > 3) {
        await $c.win.alert("Arrival Date가 저장하는 날짜로 부터 3개월 이상의 미래일 수 없습니다."); 
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.
        ed_avdt.focus();
        return false;
    }

    //ETD-ETA가 3년 이상의 과거 일 수 없다.
    if ($c.gus.cfYearsBetween(scwin._toDate(ed_ondt.getValue()), scwin._toDate(scwin.strCurDate)) > 3) {
        await $c.win.alert("Onboard Date가 3년 이상의 과거 일 수 없습니다."); 
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.
        ed_ondt.focus();
        return false;
    }

    //ETD-ETA가 3년 이상의 과거 일 수 없다.
    if ($c.gus.cfYearsBetween(scwin._toDate(ed_avdt.getValue()), scwin._toDate(scwin.strCurDate)) > 3) {
        await $c.win.alert("Arrival Date가 3년 이상의 과거 일 수 없습니다."); 
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.
        ed_avdt.focus();
        return false;
    }

    //ETA-ETD(transit time)가 150일을 초과할 수 없다.  *150일(총 운항DATE 수) : ETA날짜에서 ETD날짜를 빼고 +1 한 날짜 
    if ($c.date.diffDate(scwin._toDate(ed_ondt.getValue()), scwin._toDate(ed_avdt.getValue())) > 149){
        await $c.win.alert("Onboard Date-Arrival Date(transit time)가 150일을 초과할 수 없습니다."); 
        tab_main.setSelectedTabIndex(0);  // 1번째 탭으로 이동.
        ed_ondt.focus();
        return false;
    }

    if (ed_dept.getValue() == "") {
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Department Info"]);
        ed_dept.focus();
        return false;
    }

    if (ed_sacd.getValue() == ""){
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Salesman Info"]);
        ed_sacd.focus();
        return false;
    }

    if (ed_itcd.getValue() == ""){
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Item Info"]);
        ed_itcd.focus();
        return false;
    }

    if (ed_ediwht.getValue() == "" || ed_ediwht.getValue() == "0" ){
        ed_ediwht.setValue(ed_mftwht.getValue());
    }

    if (ed_cjdt.getValue() == "" || !$c.date.isDate(ed_cjdt.getValue())) { // cfValidateValue = date맞는지유효성검사
        await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Result Date Date"]);
        ed_cjdt.focus();
        return false;
    }

    if (ds_HouseLicenseInfo.getTotalRow() > 0) {
        if (txt_ngnm1.getValue() == "") {
            scwin.f_selectTabMenu(2);  //  TAB FOCUS  이동
            await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Nature of Goods Info"]);
            txt_ngnm1.focus();
            return false;
        }
    }

    if (ed_dept.getValue() == "1GG") {
        await $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_010, ["Department Info"]);
        ed_dept.focus();
        return false;
    }

    if (ds_customerInfo.getTotalRow() > 0) {
        if (ed_dept.getValue() != ds_customerInfo.getCellData(ds_customerInfo.getRowPosition() || 0, "col1")) {
            await $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_013);
            ed_dept.focus();
            return false;			
        }
    }

    if (await $c.gus.cfValidate([tb_searchCondition, tb_master1, gr_HouseLicenseInfo]) == false) {
        return false;
    }

    for (var i = 0; i < ds_HouseLicenseInfo.getTotalRow(); i++) {

        //면장 번호가 있을 경우 포장 갯수 , 중량은 반드시 0보다 커야 한다
        if (ds_HouseLicenseInfo.getCellData(i, "exno") != "") {
            if (ds_HouseLicenseInfo.getCellData(i, "pkgs") == "0") {
                scwin.f_selectTabMenu(2);
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["포장 갯수"]); //@는 필수입력항목입니다.
                return false;
            }

            if (ds_HouseLicenseInfo.getCellData(i, "wht") == "0") {
                scwin.f_selectTabMenu(2);
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["중량"]); //@는 필수입력항목입니다.
                return false;
            }
        }

        //분할 여부가 yes일경우 분할 차수는 필수
        if (ds_HouseLicenseInfo.getCellData(i, "elsplgb") == "Y") {
            if (ds_HouseLicenseInfo.getCellData(i, "elmid") == "") {
                scwin.f_selectTabMenu(2);
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["분할 차수 "]); //@는 필수입력항목입니다.
                return false;
            }
        }

        //동시 포장 기호가 있을 경우 동시 포장 수랑 , 단위 필
        if (ds_HouseLicenseInfo.getCellData(i, "elcogb") != "") {
            if (ds_HouseLicenseInfo.getCellData(i, "eldpkg") == "0") {
                scwin.f_selectTabMenu(2);
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["동시 포장 수량"]); //@는 필수입력항목입니다.
                return false;
            }

            if (ds_HouseLicenseInfo.getCellData(i, "eldpkgut") == "") {
                scwin.f_selectTabMenu(2);
                await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["동시포장단위"]); //@는 필수입력항목입니다.
                return false;
            }
        }
    }

    return true;
};


