//  House Bill Info Copy
//-------------------------------------------------------------------------------
scwin.f_Copy = async function() {

    if (await $c.win.confirm(scwin.MSG_LO_WRN_001)) {   //해당 B/L 번호로 복사 하시겠습니까?
        scwin.actionFlag = "Copy";
        scwin.f_DefaultValue("Copy");
        scwin.f_Set("CREATE");

        //COPY Consignee -> Customer 복사 기능 추가
        if ($c.str.trim(ed_cncd.getValue()) != "") {
            ed_ascd.setValue($c.str.trim(ed_cncd.getValue()));
            txt_asnm.setValue($c.str.trim(txt_cnnm1.getValue()));

        } else if ($c.str.trim(ed_ntcd.getValue()) != "") {
            ed_ascd.setValue($c.str.trim(ed_ntcd.getValue()));
            txt_asnm.setValue($c.str.trim(txt_ntnm1.getValue()));
        }

        ed_cjdt.setValue("");
        txt_ngnm1.setValue("");
        txt_ngnm2.setValue("");
        txt_ngnm3.setValue("");
        txt_ngnm4.setValue("");
        ed_ediwht.setValue("");

        // B/L PIC값이 없을때 등록자 아이디로 입력(PIC값이 null되는걸 방지)
        if (ed_blpic.getValue() == "") {
            txt_blpic.setValue("");
            ed_blpic.setValue(scwin.userId.replace(/[^0-9]/g, ""));
            await scwin.f_PopUp("B/L PIC", "T");
        }
    }
};


