// 화면이동
//-------------------------------------------------------------------------
scwin._getCommonParam = function() {
    return {
        iogb: scwin.hd_iogb,
        blno: ed_blno.getValue(),
        mblno: ed_mblno.getValue(),
        mhno: lc_hmhno.getValue() || "",
        kcomcd: scwin.hd_kcomcd,
        srno: ed_srno.getValue()
    };
};

// 메뉴 오픈 공통 헬퍼
scwin._openMenu = function (title, path, menuId, param) {
	$c.win.openMenu(title, path, menuId, param || {});
};

scwin.f_openPgm = function(name) {
    var commonParam = scwin._getCommonParam();
    var param = {};

    switch (name) {
        case "Freight":
            param = {
                blno: ed_blno.getValue(),
                mblno: ed_mblno.getValue(),
                kcomcd: scwin.hd_kcomcd,
                mhno: lc_hmhno.getValue() || "",
                iogb: scwin.hd_iogb,
            };
            menuInfo = {
                pgmNm: "Export House B/L Freight"
            }
            $c.win.openMenu("House Air Waybill Freight", 
                            "/ui/il/airout/aobl/ar_104_01_04b.xml", 
                            "ar_104_01_04b.xml", 
                            param,  menuInfo);
            break;

        case "PL":
            param = {
                kcomcd: scwin.hd_kcomcd,
                seaair: "A",                // sea:S,air:A
                iogb: scwin.hd_iogb,        // out:O,in:I
                blno: "",                   // house blno
                mblno: ed_mblno.getValue(), // master blno
                mhno: lc_hmhno.getValue() || "",  // mhno
            };
            $c.win.openMenu("Booking Sheet", 
                            "/ui/il/pfm/pfbs/pe_101_01_01b.xml", 
                            "pe_101_01_01b.xml", 
                            param);
            break;

        case "Booking":
            param = {
                kcomcd: scwin.hd_kcomcd,
                srno: ed_srno.getValue(),
            };
            $c.win.openMenu("Export Customer Booking", 
                            "/ui/il/airout/aobk/ar_101_01_01b.xml", 
                            "ar_101_01_01b.xml", 
                            param);
            break;

        case "EDI":
            // var strPath = "/il/ar/airedi/aedi/ar_608_01_01b.jsp?blno=" + ed_blno.Text;
            // cfTabMenuAdd( strPath , "House Air Waybill EDI Information");
            break;

        case "Find":
            param = {
                iogb: "O",
            };
            $c.win.openMenu("House B/L Search", 
                            "/ui/il/airout/aobl/ar_104_01_02b.xml", 
                            "ar_104_01_02b.xml", 
                            param);
            break;

        case "DIM":
            param = {
                kcomcd: scwin.hd_kcomcd,
                blno: ed_blno.getValue(),
                mhno: lc_hmhno.getValue() || "",
            };
            $c.win.openMenu("House Dimension", 
                            "/ui/il/airout/aobl/ar_104_01_03b.xml", 
                            "ar_104_01_03b.xml", 
                            param);
            break;

        case "Mawb":
            param = {
                kcomcd: scwin.hd_kcomcd,
                blno: ed_mblno.getValue(),
                mhno: lc_hmhno.getValue() || "",
            };
            $c.win.openMenu("Export Master B/L", 
                            "/ui/il/airout/aobl/ar_103_01_01b.xml", 
                            "ar_103_01_01b.xml", 
                            param);
            break;

        case "Print":
            param = {
                kcomcd: scwin.hd_kcomcd,
                blno: ed_blno.getValue(),
                mhno: lc_hmhno.getValue() || "",
            };
            $c.win.openMenu("House Dimension", 
                            "/ui/il/airout/aobl/ar_104_01_05b.xml", 
                            "ar_104_01_05b.xml", 
                            param);
            break;

        case "CargoManifest":
            param = {
                kcomcd: "",
                iogb: "",
                blno: ed_mblno.getValue(),
                mhno: "",
            };
            $c.win.openMenu("Cargo Manifest", 
                            "/ui/il/airout/aoth/ar_105_01_01b.xml", 
                            "ar_105_01_01b.xml", 
                            param);
            break;

        default:
            break;
    }
};


scwin.f_MasterBookingListBinding = function(gubun, dsBooking, dsHouse) {

    switch (gubun) {

        case "Retrieve":
            var bookingRowIndex = scwin._getRowIndex(dsBooking);
            var houseRowIndex = scwin._getRowIndex(dsHouse);

            dsHouse.setCellData(houseRowIndex, "mhno",   dsBooking.getCellData(bookingRowIndex, "mhno"));
            dsHouse.setCellData(houseRowIndex, "ondt",   dsBooking.getCellData(bookingRowIndex, "ondt"));
            dsHouse.setCellData(houseRowIndex, "cjdt",   dsBooking.getCellData(bookingRowIndex, "ondt"));
            dsHouse.setCellData(houseRowIndex, "ontime", dsBooking.getCellData(bookingRowIndex, "ontime"));
            dsHouse.setCellData(houseRowIndex, "fltno",  dsBooking.getCellData(bookingRowIndex, "fltno"));
            dsHouse.setCellData(houseRowIndex, "ptcd1",  dsBooking.getCellData(bookingRowIndex, "fltno").substring(0, 2));
            dsHouse.setCellData(houseRowIndex, "agcd",   dsBooking.getCellData(bookingRowIndex, "cocd"));
            dsHouse.setCellData(houseRowIndex, "agnm",   dsBooking.getCellData(bookingRowIndex, "conm"));
            dsHouse.setCellData(houseRowIndex, "dpcd",   dsBooking.getCellData(bookingRowIndex, "dpcd"));
            dsHouse.setCellData(houseRowIndex, "dstn",   dsBooking.getCellData(bookingRowIndex, "dscd"));
            dsHouse.setCellData(houseRowIndex, "dpnm",   dsBooking.getCellData(bookingRowIndex, "dpnm"));
            dsHouse.setCellData(houseRowIndex, "dscd1",  dsBooking.getCellData(bookingRowIndex, "dscd"));
            dsHouse.setCellData(houseRowIndex, "dsnm1",  dsBooking.getCellData(bookingRowIndex, "dsnm"));
            dsHouse.setCellData(houseRowIndex, "mftpkg", dsBooking.getCellData(bookingRowIndex, "ctn"));
            dsHouse.setCellData(houseRowIndex, "mftwht", dsBooking.getCellData(bookingRowIndex, "gwht"));
            dsHouse.setCellData(houseRowIndex, "avdt",   dsBooking.getCellData(bookingRowIndex, "avdt"));
            dsHouse.setCellData(houseRowIndex, "avtime", dsBooking.getCellData(bookingRowIndex, "avtime"));
            dsHouse.setCellData(houseRowIndex, "lrgb",   dsBooking.getCellData(bookingRowIndex, "srgb"));

            scwin.f_DestinationCheck();

            if (ed_ctcd.getValue() != "") {
                scwin.f_OpenCommonPopUp("Country", "T", "F", "F");
            }
            break;

        default:
            break;
    }
};


//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = function(gubun) {
    switch (gubun) {

        case "INIT": //초기화
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([btn_Update, btn_Save, btn_Delete, btn_Cancel, btn_FileDownload]);
            $c.gus.cfDisableBtnOnly([btn_Copy, pu_Freight, pu_PlSheet, pu_Dimens, pu_Print, pu_MasterBill, pu_HawbNoChange, pu_departmentChange]);
            $c.gus.cfDisableBtnOnly([Lbtn_AddRow, Lbtn_DeleteRow, Lbtn_UndoRow]);
            $c.gus.cfEnableBtnOnly([btn_Create, pu_Find]);
            scwin.f_DisablePopUpObj();

            $c.gus.cfDisableObjects([gr_HouseLicenseInfo]);
            $c.gus.cfDisableObjects([lc_lrgb]);
            $c.gus.cfDisableObjects([ed_srno]);
            $c.gus.cfDisableObjects([ed_mblno]);
            ed_blno.focus();
            break;

        case "RETRIEVE": //조회모드
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete, btn_FileDownload]);
            $c.gus.cfEnableBtnOnly([btn_Copy, pu_Find, pu_Freight, pu_PlSheet, pu_Dimens, pu_Print, pu_MasterBill, pu_HawbNoChange, pu_departmentChange]);
            $c.gus.cfDisableBtnOnly([Lbtn_AddRow, Lbtn_DeleteRow, Lbtn_UndoRow]);
            $c.gus.cfDisableObjects([gr_HouseLicenseInfo]);
            break;

        case "CREATE": //신규
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            $c.gus.cfEnableBtnOnly([Lbtn_AddRow, Lbtn_DeleteRow, Lbtn_UndoRow]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel, btn_FileDownload]);
            scwin.f_DefaultValue("Create");
            $c.gus.cfEnableObjects([gr_HouseLicenseInfo]);
            scwin.freightYn = "";
            break;

        case "UPDATE":
            $c.gus.cfDisableBtnOnly([btn_Update, btn_Create, pu_departmentChange]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Delete, btn_Cancel, btn_FileDownload]);
            $c.gus.cfEnableBtnOnly([btn_Copy, pu_Find, pu_Freight, pu_PlSheet, pu_Dimens, pu_Print, pu_MasterBill, pu_HawbNoChange]);
            $c.gus.cfEnableBtnOnly([Lbtn_AddRow, Lbtn_DeleteRow, Lbtn_UndoRow]);
            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();
            $c.gus.cfEnableObjects([gr_HouseLicenseInfo]);
            break;

        case "SAVE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel, btn_FileDownload]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Create, btn_Delete]);
            scwin.f_Set("RETRIEVE");
            break;

        case "DELETE":
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel, btn_FileDownload]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete]);
            scwin.f_Set("RETRIEVE");
            break;

        default:
            break;
    }

    if (scwin.freightYn == "-1") {
        $c.gus.cfDisableObjects([ed_dept , txt_deptnm, img_dept, ed_itcd, txt_itnm, img_itcd]); //운임 발행시 Item, Department Disable
    }
};


//-------------------------------------------------------------------------
// PopUp 이미지를 활성화 시킨다.
//-------------------------------------------------------------------------
scwin.f_EnablePopUpObj = function() {
    $c.gus.cfEnableObjects([ed_ondt, ed_avdt, ed_cjdt]);
    $c.gus.cfEnableObjects([img_shcd, img_cncd, img_ntcd, img_agcd, img_dpcd, img_sacd, img_nocd]);
    $c.gus.cfEnableObjects([img_ctcd, img_shCtcd, img_cnCtcd, img_itcd, img_sgcd, img_dept, img_mwarecd, img_warecd, img_unit, img_cucd, img_ascd, img_ascdpic, img_pncdpic]);
};

//-------------------------------------------------------------------------
// PopUp 이미지를 비활성화 시킨다.
//-------------------------------------------------------------------------
scwin.f_DisablePopUpObj = function() {
    $c.gus.cfDisableObjects([ed_ondt, ed_avdt, ed_cjdt]);
    $c.gus.cfDisableObjects([img_shcd, img_cncd, img_ntcd, udc_agcd, udc_dpcd, udc_sacd, img_nocd]);
    $c.gus.cfDisableObjects([img_ctcd, img_shCtcd, img_cnCtcd, img_itcd, img_sgcd, img_dept, img_mwarecd, img_warecd, img_unit, img_cucd, img_ascd, img_ascdpic, img_pncdpic]);
};


//행추가
scwin.f_AddRow = function(gubun) {
    var row = ds_HouseLicenseInfo.getTotalRow();
    ds_HouseLicenseInfo.insertRow(row);
    gr_HouseLicenseInfo.setFocusedCell(row, 0);

    ds_HouseLicenseInfo.setCellData(row, "kcomcd", scwin.hd_kcomcd);
    ds_HouseLicenseInfo.setCellData(row, "mhno", lc_hmhno.getValue() || "");
    ds_HouseLicenseInfo.setCellData(row, "stdt", $c.str.trim(ed_ondt.getValue()));
};

//-------------------------------------------------------------------------
// function name : f_DelRow
// function desc : 그리드  행삭제
//-------------------------------------------------------------------------
scwin.f_DeleteRow = function(gubun) {
    // ds_HouseLicenseInfo.DeleteMarked();
    var rowIdx = ds_HouseLicenseInfo.getRowPosition();
    if (ds_HouseLicenseInfo.getRowStatus(rowIdx) == "C") {
        ds_HouseLicenseInfo.removeRow(rowIdx);
    } else {
        ds_HouseLicenseInfo.deleteRow(rowIdx);
    }
};

//행취소
scwin.f_UndoRow = function(gubun) {
    // $c.data.undoRow(ds_HouseLicenseInfo, "Y");
    var rowIdx = ds_HouseLicenseInfo.getRowPosition();
    if (ds_HouseLicenseInfo.getRowStatus(rowIdx) == "C") {
        ds_HouseLicenseInfo.removeRow(rowIdx);
    } else {
        ds_HouseLicenseInfo.undoRow(rowIdx);
    }
    gr_HouseLicenseInfo.setFocusedCell(0, 0);
};


