scwin.f_OpenCommonPopUp = function(gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    switch (gubun1) {
        case "Department" :  //Department
            udc_dept.ilCommonPopUp(scwin.udc_dept_callBackFun	    // XML상의 SELECT ID
