                                    ,null ,null ,null ,null ,null ,null
                                    ,pAllSearchTF
                                    ,"Location,Code,Name"
                                    ,pNoDataCloseTF
                                    );

                cfSetReturnValue(rtnList, ed_arcd, txt_arnm);
            break;
            */

        case "Item" :  //Item
            udc_itcd.ilCommonPopUp(scwin.udc_itcd_callBackFun
                                    ,ed_itcd.getValue()
                                    ,txt_itnm.getValue()
                                    ,pWinCloseTF
