                                    ,'80,230,1,1,1,230'
                                    ,"2,3,4,5,7,8,9,10"
                                    ,null ,null ,null ,null ,null ,null
                                    ,pAllSearchTF
                                    ,"Signature,Code,Name"
                                    ,pNoDataCloseTF
                                    );
            break;

        case "Country" :  //Country
            udc_ctcd.ilCommonPopUp(scwin.udc_ctcd_callBackFun
                                    ,ed_ctcd.getValue()
                                    ,txt_ctnm.getValue()
                                    ,pWinCloseTF
                                    ,'2'
