//MHNNO 가져오기
scwin.f_MhnoLoading = function() {

    var strClntNo = $c.str.trim(ed_blno.getValue());

    ds_hmhno.removeAll();

    if (strClntNo.length > 0) {
        dma_comCode.set("sysCd", "ilCommonEBC");
        dma_comCode.set("queryId", "retriveAirHouseMhnoListCombo");
        dma_comCode.set("param1", strClntNo);
        dma_comCode.set("param2", scwin.hd_iogb);
        $c.sbm.execute(sbm_loadHmhno);

    } else {
        scwin._resetAutoComplete(lc_hmhno);
    }
};


//Master Consol No 가져오기
scwin.f_MasterConsolNoLoading = async function() {
    var strClntNo = $c.str.trim(ed_mblno.getValue());

    ds_hmhno.removeAll();

    if (strClntNo.length > 0) {
        dma_comCode.set("sysCd", "ilCommonEBC");
        dma_comCode.set("queryId", "retriveAirMasterMhnoListCombo");
        dma_comCode.set("param1", strClntNo);
        dma_comCode.set("param2", scwin.hd_iogb);
        await $c.sbm.execute(sbm_loadMasterMhno);

    } else {
        ds_hmhno.removeAll();
        scwin._resetAutoComplete(lc_hmhno);
    }
};


// Master 정보 House 화면에 Binding
scwin.f_MasterInfoBinding = function() {
    if (ds_MasterInfo.getRowCount() == 0) {
        return;
    }

    var masterRowIndex = scwin._getRowIndex(ds_MasterInfo);
    var houseRowIndex = scwin._getRowIndex(ds_HouseBillInfo);

    ds_HouseBillInfo.setCellData(houseRowIndex, "dpcd",   ds_MasterInfo.getCellData(masterRowIndex, "dpcd"));
    ds_HouseBillInfo.setCellData(houseRowIndex, "dpnm",   ds_MasterInfo.getCellData(masterRowIndex, "dpnm"));
    ds_HouseBillInfo.setCellData(houseRowIndex, "dscd1",  ds_MasterInfo.getCellData(masterRowIndex, "dstn"));
    ds_HouseBillInfo.setCellData(houseRowIndex, "dstn",   ds_MasterInfo.getCellData(masterRowIndex, "dstn"));
    ds_HouseBillInfo.setCellData(houseRowIndex, "dsnm1",  ds_MasterInfo.getCellData(masterRowIndex, "dsnm1"));
    ds_HouseBillInfo.setCellData(houseRowIndex, "fltno",  ds_MasterInfo.getCellData(masterRowIndex, "fltno"));
    ds_HouseBillInfo.setCellData(houseRowIndex, "ptcd1",  ds_MasterInfo.getCellData(masterRowIndex, "fltno").substring(0, 2));
    ds_HouseBillInfo.setCellData(houseRowIndex, "ondt",   ds_MasterInfo.getCellData(masterRowIndex, "ondt"));
    ds_HouseBillInfo.setCellData(houseRowIndex, "cjdt",   ds_MasterInfo.getCellData(masterRowIndex, "ondt"));
    ds_HouseBillInfo.setCellData(houseRowIndex, "ontime", ds_MasterInfo.getCellData(masterRowIndex, "ontm"));
    ds_HouseBillInfo.setCellData(houseRowIndex, "avdt",   ds_MasterInfo.getCellData(masterRowIndex, "avdt"));
    ds_HouseBillInfo.setCellData(houseRowIndex, "avtime", ds_MasterInfo.getCellData(masterRowIndex, "avtm"));

    if ($c.str.trim(ed_nocd.getValue()) == "") {
        ed_nocd.setValue(ds_MasterInfo.getCellData(masterRowIndex, "cncd"));
        if ($c.str.trim(ed_nocd.getValue()) != "") {
            scwin.f_PopUp("Partner", "T", "F", "F");
        }
    }

    scwin.f_DestinationCheck(); // 국가 코드 뿌려 주기 위해

    if (ed_ctcd.getValue() != "") {
        scwin.f_OpenCommonPopUp("Country", "T", "F", "F");
    }
};


//Notify Handling
scwin.f_NotifyHandling = function(gubun) {

    switch (gubun) {
        case "Same":
            ed_ntcd.setValue("");
            txt_ntnm1.setValue("SAME AS CONSIGNEE");
            txt_ntnm2.setValue("");
            txt_ntnm3.setValue("");
            txt_ntnm4.setValue("");
            txt_ntnm5.setValue("");
            break;

        case "Copy":
            ed_ntcd.setValue(ed_cncd.getValue());
            txt_ntnm1.setValue(txt_cnnm1.getValue());
            txt_ntnm2.setValue(txt_cnnm2.getValue());
            txt_ntnm3.setValue(txt_cnnm3.getValue());
            txt_ntnm4.setValue(txt_cnnm4.getValue());
            txt_ntnm5.setValue(txt_cnnm5.getValue());
            break;

        default:
            break;
    }
};


//-------------------------------------------------------------------------
//Prepaid / Collect Type Getting
//-------------------------------------------------------------------------
scwin.f_FreightTypeGetting = function() {
    chb_frpc1.setValue("0");
    chb_frpc2.setValue("0");
    chb_otpc1.setValue("0");
    chb_otpc2.setValue("0");

    //WT/VAL
    if (scwin.hd_frpc == "PP") {
        chb_frpc1.setValue("1");
    }
    if (scwin.hd_frpc == "CC") {
        chb_frpc2.setValue("1");
    }
    if (scwin.hd_frpc == "PC") {
        chb_frpc1.setValue("1");
        chb_frpc2.setValue("1");
    }

    //OTHER
    if (scwin.hd_otpc == "PP") {
        chb_otpc1.setValue("1");
    }
    if (scwin.hd_otpc == "CC") {
        chb_otpc2.setValue("1");
    }
    if (scwin.hd_otpc == "PC") {
        chb_otpc1.setValue("1");
        chb_otpc2.setValue("1");
    }
};


//-------------------------------------------------------------------------
//Prepaid / Collect Type Setting
//-------------------------------------------------------------------------
scwin.f_FreightTypeSetting = function() {
    scwin.hd_frpc = "";
    scwin.hd_otpc = "";

    // WT/VAL
    if (chb_frpc1.getValue() != "0") {
        scwin.hd_frpc = "PP";
    }
    if (chb_frpc2.getValue() != "0") {
        scwin.hd_frpc = "CC";
    }
    if (chb_frpc1.getValue() != "0" && chb_frpc2.getValue() != "0") {
        scwin.hd_frpc = "PC";
    }

    // Other
    if (chb_otpc1.getValue() != "0") {
        scwin.hd_otpc = "PP";
    }
    if (chb_otpc2.getValue() != "0") {
        scwin.hd_otpc = "CC";
    }
    if (chb_otpc1.getValue() != "0" && chb_otpc2.getValue() != "0") {
        scwin.hd_otpc = "PC";
    }
};


// Airport Destination 설정
scwin.f_AirportDestination = async function() {
    var strClntNo = "";

    if (ed_dscd1.getValue() != "") {
        strClntNo = $c.str.trim(ed_dscd1.getValue());
    }
    if (ed_dscd2.getValue() != "") {
        strClntNo = $c.str.trim(ed_dscd2.getValue());
    }
    if (ed_dscd3.getValue() != "") {
        strClntNo = $c.str.trim(ed_dscd3.getValue());
    }

    if (strClntNo != "") {
        dma_AirportInfo.set("sysCd", "ilCommonEBC");
        dma_AirportInfo.set("queryId", "retrieveAirPortCode");
        dma_AirportInfo.set("param1", strClntNo);
        dma_AirportInfo.set("param2", "");
        await $c.sbm.execute(sbm_loadAirportInfo);
        // submitDone

    } else {
        ed_dsnm1.setValue("");
    }
};


