scwin.f_admitIssue = async function() {
    if (ed_blno.getValue() == "" || ed_blno.getValue() == null) {
        await $c.win.alert("House B/L No is mandatory.");
        scwin.f_retrieveBlPrintAdmission();
        return false;
    }

    // 접속자 아이디가 B/L 발행 승인 가능한 권한 그룹에 속해있는지 조회 (AR01)
    ds_empNo.removeAll();
    scwin._insertRow(ds_empNo);
    var rowIndex = scwin._getRowIndex(ds_empNo);
    ds_empNo.setCellData(rowIndex, "empNo", scwin.empNo);
    ds_empNo.setCellData(rowIndex, "admPrtCls", "A");
    await $c.sbm.execute(sbm_RetrieveAuthGroup);

    // SubmitDone - 해당 B/L의 발행가능여부 저장
    // 발행가능("Y")이면 scwin.f_saveBlPrintAdmission 호출
};


