    ds_blPrint2.setCellData(rowIndex, "mhno", $c.str.trim(lc_hmhno.getValue() || ""));
    ds_blPrint2.setCellData(rowIndex, "seaAirCls", "A");
    ds_blPrint2.setCellData(rowIndex, "mblHblCls", "H");
    ds_blPrint2.setCellData(rowIndex, "issueYn", chk);
    ds_blPrint2.setCellData(rowIndex, "inpid", scwin.empNo);
    ds_blPrint2.setCellData(rowIndex, "updid", scwin.empNo);

    await $c.sbm.execute(sbm_SaveBlPrintAdmission);
};


scwin.f_retrieveBlPrintAdmission = function() {
