// 조회 TR EVENT(성공)
scwin.sbm_Retrieve_submitdone = async function(e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

	if (ds_HouseBillInfo.getTotalRow() == 0) {
		scwin.f_ProcessResult("None");

	} else {
	    ds_HouseBillInfo.setRowPosition(0);
        var idx = ds_HouseBillInfo.getRowPosition();

        //컴포넌트 setValue
        lc_inco.setValue(ds_HouseBillInfo.getCellData(idx, "inco"));
