        scwin.hd_otpc = ds_HouseBillInfo.getCellData(idx, "otpc");
        scwin.hd_oldmhno = ds_HouseBillInfo.getCellData(idx, "oldmhno");

		scwin.f_retrieveBlPrintAdmission();
		await scwin.f_ProcessResult("HouseInfo");
	}

    //f_Retrieve() script
    txt_blpic.setValue("");
    ed_blpic.setValue(ed_blpic.getValue().replace(/[^0-9]/g, ""));
    if (ed_blpic.getValue() != "") {
        await scwin.f_PopUp("B/L PIC", "T");
    }

    totalRow.setValue(ds_HouseLicenseInfo.getTotalRow());
};


