scwin.sbm_RetrieveHouseBillCheck_submitdone = async function(e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (ds_HouseBillCheck.getRowCount() == 0) {
        scwin.processFlag = "NotExist";
    } else {
        scwin.processFlag = "Exist";
    }

    if (scwin.processFlag == "Exist") {
        await $c.gus.cfAlertMsg(E_MSG_CM_WRN_011, ["House B/L No"]);
        ed_blno.focus();
        return false;
    } else if (scwin.processFlag == "NotExist") {
        // ds_HouseBillInfo.modifyRowStatus(ds_HouseBillInfo.getRowPosition(), "C");  //Gauce jobType : Insert 로 변경
        await scwin.f_Save_after();
    }
};


scwin.sbm_Save_submitdone = async function(e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (scwin.actionFlag == "Save") {   // 저장
        if (ds_resultHblnoMsg.getTotalRow() > 0) {
            var rowIndex = scwin._getRowIndex(ds_resultHblnoMsg);
            if ($c.str.trim(ds_resultHblnoMsg.getCellData(rowIndex, "Hblno")) != "") {
                ed_blno.setValue(ds_resultHblnoMsg.getCellData(rowIndex, "Hblno"));
            }
        }
        await $c.gus.cfAlertMsg(E_MSG_CM_INF_001);

        // f_Save script
        scwin.f_Set("SAVE");

        scwin.f_MhnoLoading();
        await scwin.f_Retrieve();
    }

    if (scwin.actionFlag == "Delete") { // 삭제
        await $c.gus.cfAlertMsg(E_MSG_CM_INF_004);	// 성공적으로 삭제하였습니다
        ed_blno.setValue("");
        ds_hmhno.removeAll();
        scwin._resetAutoComplete(lc_hmhno); // TODO: CBData 매핑 확인
        ed_blno.focus();
    }

    scwin.processFlag = "None";
};


