scwin.gr_HouseLicenseInfo_onbeforeedit = function (rowIndex, columnIndex, value) {
    var colId = gr_HouseLicenseInfo.getColumnID(columnIndex);
    if (colId == "pacd" || colId == "eldpkgut") {
        scwin.grdOldValue = value;
    }
};

scwin.gr_HouseLicenseInfo_oneditend = function (rowIndex, columnIndex, value) {
    var colId = gr_HouseLicenseInfo.getColumnID(columnIndex);

    switch (colId) {
        case "pacd":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (value != "" && value != scwin.grdOldValue) {
                ds_HouseLicenseInfo.setCellData(rowIndex, colId, value);
                scwin.f_PopUpGrid("LicenseUnit", rowIndex, "T", "F", "F");
            //Name field 존재시 check.
			//Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else if (value == "") {
                ds_HouseLicenseInfo.setCellData(rowIndex, "pacd", "");
            }
            break;

        case "eldpkgut":
            //코드값이 공백이 아닌경우 && 값이 변하였을경우 팝업을 호출한다.
            if (value != "" && value != scwin.grdOldValue) {
                ds_HouseLicenseInfo.setCellData(rowIndex, colId, value);
                scwin.f_PopUpGrid("LicenseUnit2", rowIndex, "F", "F", "F");
            //Name field 존재시 check.
			//Name Value 가 Blank 일경우 코드값을 Blank 한다.
            } else if (value == "") {
                ds_HouseLicenseInfo.setCellData(rowIndex, "eldpkgut", "");
            }
            break;

        default:
            break;
    }
};

