// submit Async
scwin.executeAsync = function(sbmObj) {
    return new Promise((resolve, reject) => {
        sbmObj.onSubmitDone = function() {
            resolve();
        };
        sbmObj.onSubmitError = function() {
            reject();
        };
        $c.sbm.execute(sbmObj);
    });
};



